SELECT value, weighted_sample_trips, unweighted_sample_trips, distance
FROM travel_data
WHERE ethnicity_id = 1 AND main_mode_id = 2;

SELECT source_name
FROM data_sources
WHERE last_updated = (SELECT MIN(last_updated) FROM data_sources);

SELECT COUNT(*) 
FROM travel_data 
WHERE main_mode_id = (SELECT mode_id FROM modes_of_transport WHERE mode_name = 'Bicycle');
